        // For 7: Divisors in S are {7}. Smallest is 7.
        // For 5: Divisors in S are {5}. Smallest is 5.
        // For 9: Divisors in S are {9}. Smallest is 9.
        // Final sum: 7 + 5 + 9 = 21. Matches.

        // This hypothesis seems correct: for each initial element, the minimum achievable value 
        // is the smallest element in the *original* set of unique values that divides it.

        // 1. Get the set of unique elements S.
        set<long long> unique_nums_set(nums.begin(), nums.end());
        vector<long long> S(unique_nums_set.begin(), unique_nums_set.end());

        // Sort S to easily find the smallest divisor
        sort(S.begin(), S.end());

        long long total_min_sum = 0;

        // 2. For each element in the original array nums:
        for (long long n_i : nums) {
            long long min_replacement = n_i;

            // 3. Find the smallest d in S such that n_i % d == 0.
            // Since S is sorted, the first divisor found will be the smallest.
            for (long long d : S) {
                if (d > n_i) {
                    // No larger divisor can divide n_i, and we are iterating in increasing order.
                    break;
                }
                if (n_i % d == 0) {
